import{_ as t,o as e,c as l,Q as n}from"./chunks/framework.6a72df8e.js";const p=JSON.parse(`{"title":"Spring_Festival与《HI，Mum!》的相关词汇","description":"","frontmatter":{"title":"Spring_Festival与《HI，Mum!》的相关词汇","date":"2021-03-08T10:39:20.000Z","tags":["笔记","大学","英语"],"published":true,"hideInList":false,"feature":null,"isTop":false},"headers":[{"level":2,"title":"牛年春节词汇特辑（Happy Lunar New Year）","slug":"牛年春节词汇特辑-happy-lunar-new-year","link":"#牛年春节词汇特辑-happy-lunar-new-year","children":[{"level":3,"title":"三牛精神","slug":"三牛精神","link":"#三牛精神","children":[{"level":4,"title":"词汇","slug":"词汇","link":"#词汇","children":[]},{"level":4,"title":"解释","slug":"解释","link":"#解释","children":[]}]},{"level":3,"title":"春节词汇","slug":"春节词汇","link":"#春节词汇","children":[]},{"level":3,"title":"“牛”的词语","slug":"牛-的词语","link":"#牛-的词语","children":[]},{"level":3,"title":"贺岁档系列","slug":"贺岁档系列","link":"#贺岁档系列","children":[]},{"level":3,"title":"People's Liberation Army (PLA)","slug":"people-s-liberation-army-pla","link":"#people-s-liberation-army-pla","children":[]}]}],"relativePath":"src/杂项/Spring_Festival与《HI，Mum!》的相关词汇.md","lastUpdated":1700455155000}`),r={name:"src/杂项/Spring_Festival与《HI，Mum!》的相关词汇.md"},a=n(`<p>概括了牛年春节的词汇，包括习主席讲话的三牛精神 《Hi,Mum》就是今年春节档贺岁片top，你好李焕英的英译名</p><h2 id="牛年春节词汇特辑-happy-lunar-new-year" tabindex="-1">牛年春节词汇特辑（Happy Lunar New Year） <a class="header-anchor" href="#牛年春节词汇特辑-happy-lunar-new-year" aria-hidden="true">#</a></h2><p><code>lunar</code> 有“月亮”的意思，lunar calendar则代表农历年，也称为旧历年，因为农历纪年法与月相有关</p><h3 id="三牛精神" tabindex="-1">三牛精神 <a class="header-anchor" href="#三牛精神" aria-hidden="true">#</a></h3><h4 id="词汇" tabindex="-1">词汇 <a class="header-anchor" href="#词汇" aria-hidden="true">#</a></h4><table><thead><tr><th style="text-align:center;">English</th><th style="text-align:center;">简体中文</th></tr></thead><tbody><tr><td style="text-align:center;">Serving-the-people ox</td><td style="text-align:center;">孺子牛</td></tr><tr><td style="text-align:center;">Pioneer ox</td><td style="text-align:center;">先驱牛</td></tr><tr><td style="text-align:center;">Persisting ox</td><td style="text-align:center;">老黄牛</td></tr></tbody></table><h4 id="解释" tabindex="-1">解释 <a class="header-anchor" href="#解释" aria-hidden="true">#</a></h4><pre><code>ox指代中性的牛，需要与cow和bull加以区分，cow是母牛，bull是公牛，一般bull有冲动的含义，
所以一般说起生肖，会用到ox，而不是bull或cow
</code></pre><p><code>Serving-the-people ox</code> 就是为人民服务的精神 <code>Pioneer ox</code> 指有initiative<sup class="footnote-ref"><a href="#fn1" id="fnref1">[1]</a></sup>（首创精神）的人 <code>Persisting ox</code> 老黄牛代表勤劳踏实</p><h3 id="春节词汇" tabindex="-1">春节词汇 <a class="header-anchor" href="#春节词汇" aria-hidden="true">#</a></h3><table><thead><tr><th style="text-align:center;">English</th><th style="text-align:center;">简体中文</th><th style="text-align:center;">词性</th></tr></thead><tbody><tr><td style="text-align:center;">festivity</td><td style="text-align:center;">节日活动</td><td style="text-align:center;">n.</td></tr><tr><td style="text-align:center;">vibrancy</td><td style="text-align:center;">活力</td><td style="text-align:center;">n.</td></tr><tr><td style="text-align:center;">diversity</td><td style="text-align:center;">多样性</td><td style="text-align:center;">n.</td></tr><tr><td style="text-align:center;">multicultural</td><td style="text-align:center;">多文化融合的</td><td style="text-align:center;">adj.</td></tr><tr><td style="text-align:center;">incredible</td><td style="text-align:center;">难以置信的</td><td style="text-align:center;">adj.</td></tr><tr><td style="text-align:center;">legacy</td><td style="text-align:center;">遗产</td><td style="text-align:center;">n.</td></tr><tr><td style="text-align:center;">dynamic country</td><td style="text-align:center;">充满活力的国家</td><td style="text-align:center;">-</td></tr><tr><td style="text-align:center;">auspicious</td><td style="text-align:center;">吉祥如意</td><td style="text-align:center;">adj.</td></tr><tr><td style="text-align:center;">firecracker</td><td style="text-align:center;">鞭炮</td><td style="text-align:center;">n.</td></tr><tr><td style="text-align:center;">zodiac animal</td><td style="text-align:center;">生肖</td><td style="text-align:center;">n.</td></tr><tr><td style="text-align:center;">gala</td><td style="text-align:center;">晚会</td><td style="text-align:center;">n.</td></tr><tr><td style="text-align:center;">feast</td><td style="text-align:center;">盛宴</td><td style="text-align:center;">n.</td></tr><tr><td style="text-align:center;">lunar calendar</td><td style="text-align:center;">旧历</td><td style="text-align:center;">n.</td></tr><tr><td style="text-align:center;">abundance</td><td style="text-align:center;">丰富的</td><td style="text-align:center;">adj.</td></tr><tr><td style="text-align:center;">red envelope</td><td style="text-align:center;">红包</td><td style="text-align:center;">n.</td></tr><tr><td style="text-align:center;">couplet</td><td style="text-align:center;">对联</td><td style="text-align:center;">n.</td></tr></tbody></table><h3 id="牛-的词语" tabindex="-1">“牛”的词语 <a class="header-anchor" href="#牛-的词语" aria-hidden="true">#</a></h3><table><thead><tr><th style="text-align:center;">English</th><th style="text-align:center;">简体中文</th></tr></thead><tbody><tr><td style="text-align:center;">be like a red rag to a bull</td><td style="text-align:center;">让人火冒三丈</td></tr><tr><td style="text-align:center;">take the bull by the horns</td><td style="text-align:center;">当机立断</td></tr><tr><td style="text-align:center;">cash cow</td><td style="text-align:center;">摇钱树</td></tr><tr><td style="text-align:center;">until the cows come home</td><td style="text-align:center;">没完没了</td></tr><tr><td style="text-align:center;">as strong as an ox</td><td style="text-align:center;">健壮如牛</td></tr><tr><td style="text-align:center;">have the constitution of an ox</td><td style="text-align:center;">健壮如牛</td></tr><tr><td style="text-align:center;">like a bull in a china shop</td><td style="text-align:center;">把事情弄糟</td></tr><tr><td style="text-align:center;">like a bull at a gate</td><td style="text-align:center;">横冲直撞</td></tr><tr><td style="text-align:center;">hit the bullseye</td><td style="text-align:center;">命中要害，正中红心</td></tr><tr><td style="text-align:center;">Don&#39;t have a cow.</td><td style="text-align:center;">不要这么upset</td></tr><tr><td style="text-align:center;">cock and bull story</td><td style="text-align:center;">诳语，胡话</td></tr></tbody></table><h3 id="贺岁档系列" tabindex="-1">贺岁档系列 <a class="header-anchor" href="#贺岁档系列" aria-hidden="true">#</a></h3><table><thead><tr><th style="text-align:center;">English</th><th style="text-align:center;">简体中文</th></tr></thead><tbody><tr><td style="text-align:center;">blockbuster</td><td style="text-align:center;">票房大卖（形容卖座）</td></tr><tr><td style="text-align:center;">sail past</td><td style="text-align:center;">驶过，超过</td></tr><tr><td style="text-align:center;">an unprecedented feat</td><td style="text-align:center;">史无前例的壮举</td></tr><tr><td style="text-align:center;">complete head-to-head</td><td style="text-align:center;">针锋相对，针尖对麦芒</td></tr><tr><td style="text-align:center;">heartwarming comedy</td><td style="text-align:center;">暖心喜剧，温馨喜剧</td></tr><tr><td style="text-align:center;">a viral phenomenon</td><td style="text-align:center;">(病毒一样的现象，类似万人空巷)</td></tr><tr><td style="text-align:center;">capture the hearts</td><td style="text-align:center;">捕获芳心</td></tr><tr><td style="text-align:center;">travel back in time</td><td style="text-align:center;">穿越到过去</td></tr><tr><td style="text-align:center;">befriend<sup class="footnote-ref"><a href="#fn2" id="fnref2">[2]</a></sup> sb.</td><td style="text-align:center;">和sb.做朋友</td></tr><tr><td style="text-align:center;">generate the highest social scores</td><td style="text-align:center;">高口碑神作</td></tr></tbody></table><blockquote><p>&quot;Birds are owned by sand track, will sail past the waves no trace.&quot; My beach Retention of your shadows, your surf there without my sigh? “鸟归沙有迹，帆过浪无痕。”我的沙滩留着你的倩影，你的浪花里有没有我的叹息？</p></blockquote><h3 id="people-s-liberation-army-pla" tabindex="-1">People&#39;s Liberation Army (PLA) <a class="header-anchor" href="#people-s-liberation-army-pla" aria-hidden="true">#</a></h3><table><thead><tr><th style="text-align:center;">English</th><th style="text-align:center;">简体中文</th></tr></thead><tbody><tr><td style="text-align:center;">wading through</td><td style="text-align:center;">涉水而过</td></tr><tr><td style="text-align:center;">negotiate</td><td style="text-align:center;">谈判</td></tr><tr><td style="text-align:center;">deploy</td><td style="text-align:center;">部署</td></tr><tr><td style="text-align:center;">fierce struggle</td><td style="text-align:center;">激烈的斗争</td></tr><tr><td style="text-align:center;">posthumous awards</td><td style="text-align:center;">遗赠奖，追赠</td></tr><tr><td style="text-align:center;">clash</td><td style="text-align:center;">冲突，打斗</td></tr><tr><td style="text-align:center;">in an attempt to</td><td style="text-align:center;">试图</td></tr><tr><td style="text-align:center;">a bloody hand to hand battle</td><td style="text-align:center;">血腥的肉搏</td></tr><tr><td style="text-align:center;">violated an agreement</td><td style="text-align:center;">违反协议</td></tr></tbody></table><hr class="footnotes-sep"><section class="footnotes"><ol class="footnotes-list"><li id="fn1" class="footnote-item"><p>initiative : [n.] 首创精神;倡议;新方案;主动性;积极性;自发性;掌握有利条件的能力(或机会);主动权. <a href="#fnref1" class="footnote-backref">↩︎</a></p></li><li id="fn2" class="footnote-item"><p>befriend : [vt.] eg:A befriend B. 意思和make friend with sb.类似，需要注意的是befriend是及物动词，不要介词。 <a href="#fnref2" class="footnote-backref">↩︎</a></p></li></ol></section>`,20),d=[a];function i(s,c,y,g,o,h){return e(),l("div",null,d)}const u=t(r,[["render",i]]);export{p as __pageData,u as default};
